THE RISK:
{
 "id": "oem-cell-odm-price-foreclosure",
 "title": "The OEM/integrator cell is already owned by Asian ODM white-label economics a CE industrial entrant cannot match",
 "narrative": "The model books 22% of PDU spend to the OEM/integrator channel as if it were open territory. But the corpus shows that channel is precisely where Taiwanese and Chinese ODMs (Digipower, GETEKnet and peers) live: rack integrators source intelligent PDUs white-label at ODM cost points, with private-label flexibility built into the sourcing terms. A Central European industrial entrant with its own manufacturing base competes in that cell on the one dimension where it is structurally weakest — landed unit cost at integrator volumes. This is not a bake-off it can lose; it is a bake-off it will never be invited to, because integrator RFQs are decided on BOM cost before any intelligence feature is evaluated. The 0.22 cell inflates SAM with spend that is priced out of reach on day one.",
 "category": "competitive",
 "targetNodes": [
  "cust.oem"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "The OEM/integrator channel for intelligent PDUs is served by established ODM white-label suppliers — Digipower supports global OEM partners from Taiwan, GETEKnet markets explicitly as an OEM rack-PDU supplier, and buyer guides list OEM/private-label options as standard distributor sourcing terms",
   "refs": [
    "digest:cust-mix#c11",
    "digest:cust-mix#c12",
    "digest:cust-mix#c13"
   ]
  },
  {
   "step": "propagation",
   "text": "Integrator purchasing is decided on landed BOM cost and private-label flexibility at volume; a pre-launch CE industrial manufacturer cannot reach ODM price points, and no corpus source quantifies OEM/ODM share precisely because the channel is opaque, commodity-priced, and relationship-locked",
   "refs": [
    "profile:Product",
    "profile:Company",
    "ledger:cust.oem"
   ]
  },
  {
   "step": "model-impact",
   "text": "The 0.22 cust.oem cell is structurally foreclosed by cost position rather than contested — carrying it in SAM overstates the venture's serviceable spend, and any GTM plan that counts integrator volume in the ramp is counting revenue from a channel that never issues it an RFQ",
   "refs": [
    "ledger:cust.oem",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "whyMissable": "The cell carries the label 'OEM/integrator' — which to an industrial manufacturer reads as its natural home turf, not enemy territory. The surface appearance is affinity ('we are a manufacturer, OEMs are our people'); the hidden reality is that in this channel the venture is the customer's competitor's customer: integrators buy from ODMs whose cost structure defines the price, and the ledger's zero-evidence 0.22 was never stress-tested against that.",
 "expectedObviousness": "low",
 "falsifier": "Quote-level comparison showing the venture can land within ~10–15% of ODM white-label pricing at integrator volumes, or a rack-integrator design win awarded on features/compliance rather than unit price.",
 "likelihood": {
  "value": 0.52,
  "rationale": "The ODM white-label channel for intelligent PDUs is directly documented in the corpus (Digipower, GETEKnet, private-label sourcing terms), and industrial-entrant cost disadvantage vs Asian ODM at volume is a robust pattern; some integrators do pay premiums for EU-origin and short lead times [evidence revision: The trigger (ODM white-label OEM channel served by Digipower/GETEKnet with volume-based pricing) is now directly confirmed rather than merely asserted, strengthening the cost-foreclosure premise slightly. But the falsifying-query results provide credible evidence that a meaningful slice of integrator/OEM PDU business is won on engineering, compliance, lead time, and intelligence features (Vertiv ETO, Schneider custom, Panduit award) — not purely lowest BOM. These offset each other, leaving the likelihood essentially at the prior with a marginal uptick from confirmed ODM channel structure.]",
  "basis": "evidence",
  "revisedFrom": 0.5
 },
 "perturbation": [
  {
   "nodeId": "cust.oem",
   "op": "exclude",
   "note": "OEM/integrator cell foreclosed by ODM cost structure — unavailable to a CE industrial entrant, not merely competitive"
  }
 ],
 "indicators": [
  {
   "signal": "ASP gap between ODM-listed intelligent PDUs and the venture's target price at integrator volumes",
   "where": "ODM published price lists and B2B marketplace listings (Digipower, GETEKnet, Alibaba-listed smart-PDU lines) vs the venture's cost model",
   "threshold": "ODM intelligent-PDU ASPs ≥30% below the venture's achievable price at 500+ unit volumes",
   "updates": "increases"
  },
  {
   "signal": "Basis-of-award in rack-integrator RFQs (price vs features/origin/compliance)",
   "where": "Integrator RFQ responses and OCP marketplace/integrated-rack product listings specifying PDU sourcing",
   "threshold": "≥2 of first 3 integrator RFQs decided on unit price with white-label requirement",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Commission a teardown and landed-cost benchmark of 3 leading ODM intelligent PDUs against the venture's BOM before building any OEM-channel revenue into the plan",
   "type": "information",
   "voiNodeId": "cust.oem",
   "note": "Directly tests whether the 0.22 cell is priced in or out of reach"
  },
  {
   "action": "Reposition for the OEM channel only where EU-manufacture matters: compliance-sensitive, short-lead-time, and sovereignty-driven builds — conceding commodity white-label volume",
   "type": "strategic",
   "voiNodeId": null,
   "note": null
  },
  {
   "action": "Explore becoming the EU-based second source for one ODM-dependent integrator facing supply-chain or customs-origin pressure",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Import dependence creates a narrow contractual wedge into an otherwise closed cell"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "OEM PDU Power Distribution Unit Solution",
   "sourceType": "industry-report",
   "publisher": "GETEKnet (Ningbo Geteknet Telecom Equipment)",
   "date": "2025-09-25",
   "excerpt": "GETEKnet is a leading OEM manufacturer and supplier of PDU... All data center PDUs are designed and manufactured under strict quality control and comply with international CE and RoHS certifications. Price changes against quantity. OEM / ODM is available.",
   "url": "https://www.getek.com/oem-pdu-power-distribution-unit-solution/",
   "attached": true
  },
  {
   "title": "The Rise of White-Label Servers: Can SMEs Reduce Their TCO Through the OCP Standard?",
   "sourceType": "industry-report",
   "publisher": "ZKKR Technology",
   "date": "2021-11-12",
   "excerpt": "Cloud computing giants... have significantly boosted their global market share... by directly sourcing white-label servers through the ODM model... in 2024, Taiwan, China, accounted for 81% of global white-label server shipments.",
   "url": "https://www.zkkrtech.com/news_detail/4.html",
   "attached": true
  },
  {
   "title": "Panduit wins prestigious Data Centre Solutions Technology Award",
   "sourceType": "industry-report",
   "publisher": "MSP Channel / Digitalisation World",
   "date": "2025-05-30",
   "excerpt": "The award went to the Panduit G6 Power Distribution Unit... underlines the best-in-class, low profile form factor and enhanced onboard intelligence required in the latest iterations of data centre compute cabinets.",
   "url": "https://www.msp-channel.com/news/69994/panduit-wins-prestigious-data-centre-solutions-technology-award",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.getek.com/oem-pdu-power-distribution-unit-solution/",
   "stance": "supports",
   "quote": "GETEKnet is a leading OEM manufacturer and supplier of PDU(Power Distribution Unit), delivering reliable power solutions for data centers, network cabinets and industrial environments."
  },
  {
   "url": "https://www.getek.com/product/smart-pdu-c13-c19-outlets-1u-19-intelligent-pdu-ats-functional-power-distribution-units-for-data-center/",
   "stance": "supports",
   "quote": "Price changes against quantity.\n\nOEM / ODM is available."
  },
  {
   "url": "https://www.digipower.com.tw/products",
   "stance": "supports",
   "quote": "DGP focus on creating Rack PDU and IP PDU. PDU series support various functions, including provide power consumption information, remote power control and remote power monitor through local current meter and network."
  },
  {
   "url": "https://www.getek.com/oem-data-center-solution/",
   "stance": "supports",
   "quote": "We offer complete flexibility in cabinet design with customizable dimensions, layouts, and internal configurations."
  },
  {
   "url": "https://www.msp-channel.com/news/69994/panduit-wins-prestigious-data-centre-solutions-technology-award",
   "stance": "contradicts",
   "quote": "This year, the award went to the Panduit G6 Power Distribution Unit, a leading PDU developed for data centre environments."
  },
  {
   "url": "https://www.vertiv.com/49794e/globalassets/products/critical-power/power-distribution/vertiv-geist-custom-rack-pdus-data-sheet.pdf",
   "stance": "contradicts",
   "quote": "Vertiv enables users to design their own solution custom-tailored for their application. Our dedicated on-site engineering, reliability, conformance, compliance, and sales support teams provide customers with direct access to participate in designing and manufacturing unique rPDU configurations to meet their requirements."
  },
  {
   "url": "https://cloudswit.ch/blogs/go-branded-switch-or-embrace-white-box-switch/",
   "stance": "supports",
   "quote": "White-box switches are the new market leaders with their flexible configurations, lower costs and higher customisability."
  }
 ]
}

